import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv is None:
        changes.append((proj, tfm, pkg, '-', av, 'Added'))
    elif av is None:
        changes.append((proj, tfm, pkg, bv, '-', 'Removed'))
    elif bv != av:
        changes.append((proj, tfm, pkg, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((proj, tfm, pkg, av))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<15} {\"TFM\":<8} {\"Package\":<48} {\"Before\":<10} {\"After\":<10} Status')
    print('-'*120)
    for c in changes:
        print(f'{c[0]:<15} {c[1]:<8} {c[2]:<48} {c[3]:<10} {c[4]:<10} {c[5]}')
else:
    print('No changes detected.')

print()
print('UNCHANGED:')
print(f'{\"Project\":<15} {\"TFM\":<8} {\"Package\":<48} Version')
print('-'*90)
for u in unchanged:
    print(f'{u[0]:<15} {u[1]:<8} {u[2]:<48} {u[3]}')
